/*
 * ceilf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly ceilf  (test_ceilf_opt.elf)
 *   2. Linked with toolchain's default ceilf        (test_ceilf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += ceilf(vx);
#else
    float r = ceilf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 -> ceil = 1.0 */
    emit_u(0x80000001u);  /* min negative subnormal -> ceil = -0.0 */
    emit_u(0x00400000u);  /* mid positive subnormal -> ceil = 1.0 */
    emit_u(0x80400000u);  /* mid negative subnormal -> ceil = -0.0 */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN -> ceil = 1.0 */
    emit_u(0x807fffffu);  /* max negative subnormal -> ceil = -0.0 */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(FLT_MIN);                /* 2^-126 = 0x00800000 -> ceil = 1.0 */
    emit(-FLT_MIN);               /* -2^-126 -> ceil = -0.0 */
    emit_u(0x7f7fffffu);          /* FLT_MAX -> ceil = FLT_MAX (already integer) */
    emit_u(0xff7fffffu);          /* -FLT_MAX -> ceil = -FLT_MAX */

    /* --- Section 4: Near 1.0 ULP neighbors (6) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 = 0.9999999... -> ceil = 1.0 */
    emit(1.0f);           /* exactly 1.0 -> ceil = 1.0 */
    emit_u(0x3f800001u);  /* one ULP above 1.0 -> ceil = 2.0 */
    emit(-1.0f);          /* exactly -1.0 -> ceil = -1.0 */
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 -> ceil = -0.0 */
    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 -> ceil = -1.0 */

    /* --- Section 5: Half-integer values (8) --- */
    emit(0.5f);    /* -> ceil = 1.0 */
    emit(-0.5f);   /* -> ceil = -0.0 */
    emit(1.5f);    /* -> ceil = 2.0 */
    emit(-1.5f);   /* -> ceil = -1.0 */
    emit(2.5f);    /* -> ceil = 3.0 */
    emit(-2.5f);   /* -> ceil = -2.0 */
    emit(7.5f);    /* -> ceil = 8.0 */
    emit(-7.5f);   /* -> ceil = -7.0 */

    /* --- Section 6: Integer boundary fractional offsets (16) --- */
    emit(0.9999999f);   /* just below 1.0 -> ceil = 1.0 */
    emit(1.0000001f);   /* just above 1.0 -> ceil = 2.0 */
    emit(-0.9999999f);  /* just above -1.0 -> ceil = -0.0 */
    emit(-1.0000001f);  /* just below -1.0 -> ceil = -1.0 */
    emit(1.9999999f);   /* just below 2.0 -> ceil = 2.0 */
    emit(2.0000001f);   /* just above 2.0 -> ceil = 3.0 */
    emit(-1.9999999f);  /* just above -2.0 -> ceil = -1.0 */
    emit(-2.0000001f);  /* just below -2.0 -> ceil = -2.0 */
    emit(4.9999999f);   /* just below 5.0 -> ceil = 5.0 */
    emit(5.0000001f);   /* just above 5.0 -> ceil = 6.0 */
    emit(-4.9999999f);  /* -> ceil = -4.0 */
    emit(-5.0000001f);  /* -> ceil = -5.0 */
    emit(9.9999990f);   /* just below 10.0 -> ceil = 10.0 */
    emit(10.000001f);   /* just above 10.0 -> ceil = 11.0 */
    emit(-9.9999990f);  /* -> ceil = -9.0 */
    emit(-10.000001f);  /* -> ceil = -10.0 */

    /* --- Section 7: ULP neighbors of integer values 2 through 5 (12) --- */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 -> ceil = 2.0 */
    emit(2.0f);           /* exactly 2.0 -> ceil = 2.0 */
    emit_u(0x40000001u);  /* one ULP above 2.0 -> ceil = 3.0 */
    emit_u(0xbfffffffu);  /* one ULP toward zero from -2.0 -> ceil = -1.0 */
    emit(-2.0f);          /* exactly -2.0 -> ceil = -2.0 */
    emit_u(0xc0000001u);  /* one ULP away from zero from -2.0 -> ceil = -2.0 */
    emit_u(0x407fffffu);  /* one ULP below 4.0 -> ceil = 4.0 */
    emit(4.0f);           /* exactly 4.0 -> ceil = 4.0 */
    emit_u(0x40800001u);  /* one ULP above 4.0 -> ceil = 5.0 */
    emit_u(0xc07fffffu);  /* one ULP toward zero from -4.0 -> ceil = -3.0 */
    emit(-4.0f);          /* exactly -4.0 -> ceil = -4.0 */
    emit_u(0xc0800001u);  /* one ULP away from zero from -4.0 -> ceil = -4.0 */

    /* --- Section 8: Large values near float integer-only threshold (10) --- */
    /* Above 2^23 = 8388608.0f all float values are exact integers */
    emit_u(0x4b000000u);  /* 2^23 = 8388608.0 -> ceil = 8388608.0 */
    emit_u(0x4b000001u);  /* 2^23 + 1 ulp -> ceil = same (exact integer) */
    emit_u(0x4affffffu);  /* one ULP below 2^23 -> ceil = 8388608.0 */
    emit_u(0xcb000000u);  /* -2^23 -> ceil = -8388608.0 */
    emit_u(0xcaffffffu);  /* one ULP toward zero from -2^23 -> ceil = -8388607.0 */
    emit(1.0e7f);         /* 10^7 > 2^23, exact integer -> ceil = 1.0e7 */
    emit(-1.0e7f);        /* -> ceil = -1.0e7 */
    emit(1.0e10f);        /* large float, exact integer -> ceil = 1.0e10 */
    emit(-1.0e10f);       /* -> ceil = -1.0e10 */
    emit_u(0x7f7ffffeu);  /* one ULP below FLT_MAX -> ceil = FLT_MAX */

    /* --- Section 9: Fractional values in (0,1) and (-1,0) (13) --- */
    emit(0.125f);    /* 1/8 -> ceil = 1.0 */
    emit(-0.125f);   /* -> ceil = -0.0 */
    emit(0.25f);     /* 1/4 -> ceil = 1.0 */
    emit(-0.25f);    /* -> ceil = -0.0 */
    emit(0.375f);    /* 3/8 -> ceil = 1.0 */
    emit(-0.375f);   /* -> ceil = -0.0 */
    emit(0.625f);    /* 5/8 -> ceil = 1.0 */
    emit(-0.625f);   /* -> ceil = -0.0 */
    emit(0.75f);     /* 3/4 -> ceil = 1.0 */
    emit(-0.75f);    /* -> ceil = -0.0 */
    emit(0.875f);    /* 7/8 -> ceil = 1.0 */
    emit(-0.875f);   /* -> ceil = -0.0 */
    emit(0.1f);      /* irrational in float -> ceil = 1.0 */

    /* --- Section 10: Mixed fractional values at higher magnitudes (18) --- */
    emit(3.1f);     /* -> ceil = 4.0 */
    emit(-3.1f);    /* -> ceil = -3.0 */
    emit(3.9f);     /* -> ceil = 4.0 */
    emit(-3.9f);    /* -> ceil = -3.0 */
    emit(10.1f);    /* -> ceil = 11.0 */
    emit(-10.1f);   /* -> ceil = -10.0 */
    emit(10.9f);    /* -> ceil = 11.0 */
    emit(-10.9f);   /* -> ceil = -10.0 */
    emit(100.5f);   /* -> ceil = 101.0 */
    emit(-100.5f);  /* -> ceil = -100.0 */
    emit(1000.1f);  /* -> ceil = 1001.0 */
    emit(-1000.1f); /* -> ceil = -1000.0 */
    emit(1000.9f);  /* -> ceil = 1001.0 */
    emit(-1000.9f); /* -> ceil = -1000.0 */
    emit_u(0x3f490fdbu);  /* pi/4 ~ 0.785 -> ceil = 1.0 */
    emit_u(0xbf490fdbu);  /* -pi/4 -> ceil = -0.0 */
    emit_u(0x3fc90fdbu);  /* pi/2 ~ 1.571 -> ceil = 2.0 */
    emit_u(0xbfc90fdbu);  /* -pi/2 -> ceil = -1.0 */
}

/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                  */
/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* Sweep [0, 10] in 200 steps */
static void test_sweep(void)
{
    float hi = 10.0f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += ceilf(vx);
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf result: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

